const customers = [
  {
    customer_id: 'B2B-1023',
    company_name: 'Demo Manufacturing Co.',
    account_owner: 'sales-team-a',
    churn_probability: 0.82,
    risk_level: 'Critical',
    expected_revenue_loss: 173000,
    recent_usage_trend: '30일 사용량 28% 감소, 비활성 회선 증가',
    response_status: '미대응',
    is_vip_customer: true
  },
  {
    customer_id: 'B2B-2081',
    company_name: 'Sample Logistics Ltd.',
    account_owner: 'sales-team-b',
    churn_probability: 0.44,
    risk_level: 'Medium',
    expected_revenue_loss: 46000,
    recent_usage_trend: '사용량은 안정적이나 모바일 매출 비중 하락',
    response_status: '모니터링',
    is_vip_customer: false
  }
];

return customers.map((customer) => ({
  json: {
    run_date: new Date().toISOString(),
    workflow_stage: 'fetch_crm',
    source_system: 'Baza Telecom v2 CRM demo batch',
    ...customer
  }
}));

return $input.all().map((item) => {
  const marketPressureScore = item.json.is_vip_customer ? 0.72 : 0.38;
  return {
    json: {
      ...item.json,
      workflow_stage: 'competitor_search',
      competitor_trends: [
        '경쟁사 B2B 모바일 회선 할인 프로모션 진행',
        '기업 전용 결합 요금제 가격 인하',
        '장기 약정 고객 대상 무료 컨설팅 캠페인 진행'
      ],
      market_pressure_score: marketPressureScore,
      search_summary: `경쟁사 동향 반영, 시장 압박 점수 ${marketPressureScore}`
    }
  };
});

return $input.all().map((item) => {
  const criticalDrop = item.json.churn_probability >= 0.7;
  return {
    json: {
      ...item.json,
      workflow_stage: 'tool_shap_tensor',
      shap_top_features: [
        { feature: 'Inactive_Ratio', contribution: criticalDrop ? 0.31 : 0.12 },
        { feature: 'Revenue_per_Active_Sub', contribution: criticalDrop ? 0.26 : 0.09 },
        { feature: 'Momentum_30d', contribution: criticalDrop ? 0.22 : 0.07 }
      ],
      tensor_summary: {
        input_shape: 'Customer x 30 Days x 3 Features',
        energy_pattern: criticalDrop ? 'decreasing' : 'stable',
        momentum_pattern: criticalDrop ? 'negative acceleration' : 'flat',
        acceleration_pattern: criticalDrop ? 'risk spike near final period' : 'no sharp drop'
      }
    }
  };
});

return $input.all().map((item) => {
  const topFeatureText = item.json.shap_top_features
    .map((feature) => `${feature.feature}(${feature.contribution})`)
    .join(', ');

  return {
    json: {
      ...item.json,
      workflow_stage: 'agent_analyst',
      analyst_report: {
        role: 'Analyst',
        title: '이탈 원인 심층 진단',
        diagnosis: `${item.json.customer_id}는 ${item.json.recent_usage_trend} 패턴을 보입니다. 주요 SHAP 근거는 ${topFeatureText}입니다.`,
        evidence: item.json.tensor_summary
      }
    }
  };
});

return $input.all().map((item) => {
  const baseline = item.json.churn_probability;
  const discountScenario = Math.max(0.01, baseline - 0.12);
  const directCallScenario = Math.max(0.01, baseline - 0.09);
  const bundleScenario = Math.max(0.01, baseline - 0.16);

  return {
    json: {
      ...item.json,
      workflow_stage: 'tool_what_if',
      what_if_simulation: {
        baseline_probability: baseline,
        scenarios: [
          { action: '10% discount', expected_probability: discountScenario, action_cost: 30000 },
          { action: 'direct account call', expected_probability: directCallScenario, action_cost: 10000 },
          { action: 'bundle retention offer', expected_probability: bundleScenario, action_cost: 45000 }
        ]
      }
    }
  };
});

return $input.all().map((item) => {
  const bestScenario = item.json.what_if_simulation.scenarios
    .slice()
    .sort((a, b) => a.expected_probability - b.expected_probability)[0];

  return {
    json: {
      ...item.json,
      workflow_stage: 'agent_strategist',
      selected_retention_action: bestScenario,
      strategist_report: {
        role: 'Strategist',
        title: '방어 전략 수립',
        recommendation: `${bestScenario.action} 전략을 우선 적용하면 이탈 확률을 ${(bestScenario.expected_probability * 100).toFixed(1)}%까지 낮출 수 있습니다.`,
        expected_cost: bestScenario.action_cost
      }
    }
  };
});

return $input.all().map((item) => ({
  json: {
    ...item.json,
    workflow_stage: 'tool_slack_gmail_api',
    notification_targets: {
      slack_channel: item.json.risk_level === 'Critical' ? '#churn-alert-high' : '#churn-alert',
      gmail_to: `${item.json.account_owner}@example.com`,
      gmail_cc: 'retention-manager@example.com'
    }
  }
}));

return $input.all().map((item) => {
  const probability = (item.json.churn_probability * 100).toFixed(1);
  const loss = item.json.expected_revenue_loss.toLocaleString();
  const action = item.json.selected_retention_action.action;

  return {
    json: {
      ...item.json,
      workflow_stage: 'agent_communicator',
      communicator_report: {
        role: 'Communicator',
        title: '맞춤형 메시징 생성',
        slack_message: `[${item.json.risk_level}] ${item.json.company_name} 이탈 위험 ${probability}% 감지. 권장 액션: ${action}`,
        gmail_subject: `[ChurnRadar] ${item.json.customer_id} 이탈 위험 대응 요청`,
        gmail_body: `고객 ${item.json.company_name}의 이탈 위험이 감지되었습니다. 예상 손실은 ${loss}원입니다. 분석 근거: ${item.json.analyst_report.diagnosis} 권장 전략: ${item.json.strategist_report.recommendation}`,
        sales_script: `안녕하세요. 최근 서비스 이용 패턴을 점검해보니 일부 사용량 변화가 확인되어 연락드렸습니다. 현재 조건에서 ${action} 혜택을 제안드릴 수 있습니다.`
      }
    }
  };
});

return $input.all().map((item) => ({
  json: {
    ...item.json,
    workflow_stage: 'tool_google_sheets_mlflow',
    logging_targets: {
      google_sheet: 'churn_log',
      mlflow_experiment: 'churnradar_daily_retention',
      feedback_key: `${item.json.customer_id}-${Date.now()}`
    }
  }
}));

return $input.all().map((item) => {
  const highRiskOrHighCost = item.json.churn_probability >= 0.7 || item.json.expected_revenue_loss >= 100000;

  return {
    json: {
      ...item.json,
      workflow_stage: 'agent_auditor',
      high_risk_or_high_cost: highRiskOrHighCost,
      approval_required: highRiskOrHighCost,
      auditor_report: {
        role: 'Auditor',
        title: '성과 기록 및 검계',
        audit_status: 'passed',
        log_policy: 'prediction, action, approval, and feedback fields must be stored',
        monitoring_tags: ['daily_batch', 'multi_agent', highRiskOrHighCost ? 'approval_required' : 'auto_action']
      }
    }
  };
});

return $input.all().map((item) => ({
  json: {
    ...item.json,
    workflow_stage: 'admin_approval',
    approval_status: 'approved',
    approved_by: 'demo-admin',
    approval_note: '데모에서는 자동 승인 처리합니다. 실제 운영에서는 Wait/Webhook 또는 Slack 승인 버튼으로 교체하세요.'
  }
}));

return $input.all().map((item) => ({
  json: {
    ...item.json,
    workflow_stage: 'action_slack_gmail',
    action_sent: true,
    action_channel: 'Slack/Gmail',
    slack_payload: {
      channel: item.json.notification_targets.slack_channel,
      text: item.json.communicator_report.slack_message
    },
    gmail_payload: {
      to: item.json.notification_targets.gmail_to,
      cc: item.json.notification_targets.gmail_cc,
      subject: item.json.communicator_report.gmail_subject,
      body: item.json.communicator_report.gmail_body
    }
  }
}));

return $input.all().map((item) => ({
  json: {
    customer_id: item.json.customer_id,
    output_type: 'Slack 긴급 알림',
    slack_payload: item.json.slack_payload,
    action_sent: item.json.action_sent
  }
}));

return $input.all().map((item) => ({
  json: {
    customer_id: item.json.customer_id,
    output_type: '영업 대응 스크립트',
    sales_script: item.json.communicator_report.sales_script,
    recommended_action: item.json.selected_retention_action
  }
}));

return $input.all().map((item) => {
  const logRow = {
    timestamp: new Date().toISOString(),
    customer_id: item.json.customer_id,
    company_name: item.json.company_name,
    churn_probability: item.json.churn_probability,
    risk_level: item.json.risk_level,
    expected_revenue_loss: item.json.expected_revenue_loss,
    high_risk_or_high_cost: item.json.high_risk_or_high_cost,
    approval_required: item.json.approval_required,
    approval_status: item.json.approval_status || 'not_required',
    action_sent: item.json.action_sent,
    action_channel: item.json.action_channel,
    analyst_output: item.json.analyst_report.diagnosis,
    strategist_output: item.json.strategist_report.recommendation,
    monitoring_status: 'logged_for_feedback_loop'
  };

  return {
    json: {
      workflow_stage: 'google_sheets_monitoring',
      output_type: '성과 추적 리포트',
      google_sheets_operation: 'append_row_preview',
      mlflow_operation: 'log_metric_preview',
      log_row: logRow
    }
  };
});

return $input.all().map((item) => ({
  json: {
    workflow_stage: 'feedback_loop',
    feedback_target: 'FastAPI retraining / threshold update queue',
    feedback_payload: {
      customer_id: item.json.log_row.customer_id,
      churn_probability: item.json.log_row.churn_probability,
      action_sent: item.json.log_row.action_sent,
      approval_status: item.json.log_row.approval_status,
      monitoring_status: item.json.log_row.monitoring_status
    },
    note: 'n8n은 실제 순환 연결 대신 이 노드에서 FastAPI 재학습/모니터링 큐로 feedback payload를 전달하는 구조로 표현합니다.'
  }
}));
